-- V4__create_categories_and_backfill.sql

-- Step 1: Create categories table
CREATE TABLE categories (
    code VARCHAR(50) PRIMARY KEY,
    name VARCHAR(100) NOT NULL
);

-- Step 2: Seed categories
INSERT INTO categories (code, name) VALUES
    ('ELECTRONICS', 'Electronics'),
    ('FASHION',     'Fashion & Clothing'),
    ('GROCERY',     'Grocery & Food');

-- Step 3: Backfill category_code for existing products
UPDATE products SET category_code = 'ELECTRONICS'
    WHERE LOWER(category) LIKE '%electron%'
       OR LOWER(category) LIKE '%mobile%'
       OR LOWER(category) LIKE '%laptop%';

UPDATE products SET category_code = 'FASHION'
    WHERE LOWER(category) LIKE '%fashion%'
       OR LOWER(category) LIKE '%clothing%'
       OR LOWER(category) LIKE '%apparel%';

UPDATE products SET category_code = 'GROCERY'
    WHERE LOWER(category) LIKE '%grocer%'
       OR LOWER(category) LIKE '%food%';

-- Default for any unmatched:
UPDATE products SET category_code = 'ELECTRONICS'
    WHERE category_code IS NULL;

-- Step 4: Now safe to add NOT NULL constraint
ALTER TABLE products ALTER COLUMN category_code SET NOT NULL;
ALTER TABLE products ADD CONSTRAINT fk_product_category
    FOREIGN KEY (category_code) REFERENCES categories(code);

