import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.math.BigDecimal;

@DataJpaTest  // loads H2 + JPA only, no web layer, no real DB
class PaymentRepositoryTest {
    @Autowired PaymentRepository repo;

    @Test void save_assignsId() {
        Payment p = repo.save(new Payment("M001", new BigDecimal("999.00")));
        assertNotNull(p.getId());
        assertEquals("CREATED", p.getStatus());
    }
    @Test void findByMerchantId_returnsPayments() {
        repo.save(new Payment("M001", new BigDecimal("500.00")));
        repo.save(new Payment("M001", new BigDecimal("200.00")));
        repo.save(new Payment("M002", new BigDecimal("100.00")));
        assertEquals(2, repo.findByMerchantId("M001").size());
    }
    @Test void findByStatus_returnsCorrect() {
        Payment p = repo.save(new Payment("M001", new BigDecimal("500.00")));
        p.setStatus("CAPTURED");
        repo.save(p);
        repo.save(new Payment("M002", new BigDecimal("100.00")));
        assertEquals(1, repo.findByStatus("CAPTURED").size());
        assertEquals(1, repo.findByStatus("CREATED").size());
    }
}

