import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import javax.sql.DataSource;
import java.sql.*;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@SpringBootTest  // full context + Flyway runs migrations against CI PostgreSQL
@org.springframework.test.context.ActiveProfiles("ci")
class MigrationVerificationTest {
    @Autowired DataSource dataSource;

    @Test void flyway_appliedAllMigrations() throws Exception {
        try (Connection conn = dataSource.getConnection();
             ResultSet rs = conn.createStatement().executeQuery(
                 "SELECT COUNT(*) FROM flyway_schema_history WHERE success = true")) {
            rs.next();
            assertTrue(rs.getInt(1) >= 3, "Expected at least 3 applied migrations");
        }
    }

    @Test void orders_tableExists() throws Exception {
        try (Connection conn = dataSource.getConnection();
             ResultSet rs = conn.createStatement().executeQuery(
                 "SELECT COUNT(*) FROM orders")) {
            rs.next();
            assertEquals(0, rs.getInt(1)); // empty but table exists
        }
    }
}

// CI pipeline (GitHub Actions):
// 1. docker compose -f docker-compose-ci.yml up -d
// 2. mvn test -Dspring.profiles.active=ci   (runs MigrationVerificationTest)
// 3. docker compose -f docker-compose-ci.yml down
// 4. If tests pass → deploy to production (Flyway runs V4+ there)

