import jakarta.persistence.*;
@Entity @Table(name="trades")
public class Trade {
    @Id @GeneratedValue(strategy=GenerationType.UUID) private String id;
    @Column(name="user_id",nullable=false) private String userId;
    @Column(nullable=false) private String symbol;
    @Column(nullable=false) private int qty;
    @Column(nullable=false) private java.math.BigDecimal price;
    @Column(name="trade_type",nullable=false) private String tradeType;
    protected Trade(){}
    public Trade(String uid,String sym,int qty,java.math.BigDecimal price,String type){
        userId=uid;symbol=sym;this.qty=qty;this.price=price;tradeType=type;
    }
    public String getId(){return id;} public String getUserId(){return userId;}
    public String getSymbol(){return symbol;}
}

import org.springframework.data.jpa.repository.JpaRepository;
import java.util.*;
public interface TradeRepository extends JpaRepository<Trade,String>{
    List<Trade> findByUserId(String userId);
}

